pub enum LIoOpView<IdType, MessageType> {
    Send { s: LPacket<IdType, MessageType> },
    Receive { r: LPacket<IdType, MessageType> },
    TimeoutReceive {},
    ReadClock { t: int },
}

impl<IdType, MessageType> View for LIoOp<IdType, MessageType> {
    type V = LIoOpView<IdType, MessageType>;
    closed spec fn view(&self) -> Self::V {
        match self {
            LIoOp::Send { s } => LIoOpView::Send { s: *s },
            LIoOp::Receive { r } => LIoOpView::Receive { r: *r },
            LIoOp::TimeoutReceive {} => LIoOpView::TimeoutReceive {},
            LIoOp::ReadClock { t } => LIoOpView::ReadClock { t: *t },
        }
    }
}

